import{_ as o,o as t,c as i,ak as a}from"./chunks/framework.Dx0ZwfXr.js";const m=JSON.parse('{"title":"DisplayConfiguration","description":"","frontmatter":{},"headers":[],"relativePath":"api/reference/royalapps-community-rdp-winforms-configuration-display-displayconfiguration.md","filePath":"api/reference/royalapps-community-rdp-winforms-configuration-display-displayconfiguration.md"}'),r={name:"api/reference/royalapps-community-rdp-winforms-configuration-display-displayconfiguration.md"};function n(s,e,l,c,d,h){return t(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="displayconfiguration" tabindex="-1"><code>DisplayConfiguration</code> <a class="header-anchor" href="#displayconfiguration" aria-label="Permalink to “DisplayConfiguration”">​</a></h1><p>The display settings used for the remote desktop session.</p><h2 id="type" tabindex="-1">Type <a class="header-anchor" href="#type" aria-label="Permalink to “Type”">​</a></h2><div class="language-csharp"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">RoyalApps.Community.Rdp.WinForms.Configuration.Display.DisplayConfiguration</span></span></code></pre></div><h2 id="properties" tabindex="-1">Properties <a class="header-anchor" href="#properties" aria-label="Permalink to “Properties”">​</a></h2><h3 id="autoscaling-bool" tabindex="-1"><code>AutoScaling</code> (<code>bool</code>) <a class="header-anchor" href="#autoscaling-bool" aria-label="Permalink to “AutoScaling (bool)”">​</a></h3><p>If set to true, DPI scaling will be applied automatically.</p><h3 id="colordepth-colordepth-↗" tabindex="-1"><code>ColorDepth</code> (<a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-configuration-display-colordepth">ColorDepth</a>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclient-colordepth" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#colordepth-colordepth-↗" aria-label="Permalink to “ColorDepth (ColorDepth) ↗”">​</a></h3><p>The color depth (in bits per pixel) for the control&#39;s connection. Values include 8, 15, 16, 24, and 32 bits per pixel.</p><h3 id="containerhandledfullscreen-bool-↗" tabindex="-1"><code>ContainerHandledFullScreen</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imstscadvancedsettings-containerhandledfullscreen" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#containerhandledfullscreen-bool-↗" aria-label="Permalink to “ContainerHandledFullScreen (bool) ↗”">​</a></h3><p>Specifies whether the container-handled full-screen mode is enabled.</p><h3 id="desktopheight-int-↗" tabindex="-1"><code>DesktopHeight</code> (<code>int</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imstscax-desktopheight" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#desktopheight-int-↗" aria-label="Permalink to “DesktopHeight (int) ↗”">​</a></h3><p>Specifies the current control&#39;s height, in pixels, on the initial remote desktop. Setting the DesktopHeight property is optional, but it must be set before calling the Connect method. If a desktop height is not specified, or is set to zero, the desktop height is set to the height of the control. The minimum and maximum values are dependent upon the operating system version of the Remote Desktop client.</p><h3 id="desktopwidth-int-↗" tabindex="-1"><code>DesktopWidth</code> (<code>int</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imstscax-desktopwidth" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#desktopwidth-int-↗" aria-label="Permalink to “DesktopWidth (int) ↗”">​</a></h3><p>Specifies the current control&#39;s width, in pixels, on the initial remote desktop. Setting the DesktopWidth property is optional, but it must be set before calling the Connect method. If a desktop width is not specified, or is set to zero, the desktop width is set to the width of the control. The minimum and maximum values are dependent upon the operating system version of the Remote Desktop client.</p><h3 id="displayconnectionbar-bool-↗" tabindex="-1"><code>DisplayConnectionBar</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings-displayconnectionbar" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#displayconnectionbar-bool-↗" aria-label="Permalink to “DisplayConnectionBar (bool) ↗”">​</a></h3><p>Specifies whether to use the connection bar. The default value is true, which enables the property.</p><h3 id="fullscreen-bool-↗" tabindex="-1"><code>FullScreen</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclient-fullscreen" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#fullscreen-bool-↗" aria-label="Permalink to “FullScreen (bool) ↗”">​</a></h3><p>Determines whether the client control is in full-screen mode. True to enter full-screen mode, False to leave full-screen mode and return to window mode. Note: You can set this property when the control is connected.</p><h3 id="fullscreentitle-string-↗" tabindex="-1"><code>FullScreenTitle</code> (<code>string</code>?) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imstscax-fullscreentitle" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#fullscreentitle-string-↗" aria-label="Permalink to “FullScreenTitle (string?) ↗”">​</a></h3><p>Specifies the window title displayed when the control is in full-screen mode.</p><h3 id="hasdesktopsize-bool" tabindex="-1"><code>HasDesktopSize</code> (<code>bool</code>) <a class="header-anchor" href="#hasdesktopsize-bool" aria-label="Permalink to “HasDesktopSize (bool)”">​</a></h3><p>Return true if a desktop width and height is set.</p><h3 id="initialzoomlevel-int" tabindex="-1"><code>InitialZoomLevel</code> (<code>int</code>) <a class="header-anchor" href="#initialzoomlevel-int" aria-label="Permalink to “InitialZoomLevel (int)”">​</a></h3><p>The initial zoom level in percent (default is 100).</p><h3 id="pinconnectionbar-bool-↗" tabindex="-1"><code>PinConnectionBar</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientadvancedsettings-pinconnectionbar" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#pinconnectionbar-bool-↗" aria-label="Permalink to “PinConnectionBar (bool) ↗”">​</a></h3><p>Specifies the state of the UI connection bar. Setting this property to true sets the state to &quot;lowered&quot;, that is, invisible to the user and unavailable for input. False sets the state to &quot;raised&quot; and available for user input.</p><h3 id="resizebehavior-resizebehavior" tabindex="-1"><code>ResizeBehavior</code> (<a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-configuration-display-resizebehavior">ResizeBehavior</a>) <a class="header-anchor" href="#resizebehavior-resizebehavior" aria-label="Permalink to “ResizeBehavior (ResizeBehavior)”">​</a></h3><p>The behavior when the control is resized.</p><h3 id="uselocalscaling-bool" tabindex="-1"><code>UseLocalScaling</code> (<code>bool</code>) <a class="header-anchor" href="#uselocalscaling-bool" aria-label="Permalink to “UseLocalScaling (bool)”">​</a></h3><p>Use local scaling instead of setting the DPI in the remote session. This applies the zoom level locally without changing the remote session DPI.</p><h3 id="usemultimon-bool-↗" tabindex="-1"><code>UseMultimon</code> (<code>bool</code>) <a class="api-member-external-link" href="https://docs.microsoft.com/en-us/windows/win32/termserv/imsrdpclientnonscriptable5-usemultimon" target="_blank" rel="noreferrer" title="Open external reference">↗</a> <a class="header-anchor" href="#usemultimon-bool-↗" aria-label="Permalink to “UseMultimon (bool) ↗”">​</a></h3><p>Specifies whether the Remote Desktop ActiveX control should use multiple monitors. If this property is true, the control will use multiple monitors. If this property is false, the control will not use multiple monitors. Note: You cannot set this property while the connection has been established. Support: embedded and external sessions. External mode writes the standard <code>use multimon</code> RDP property. In external mode, selective monitor targeting is configured through <a href="/royalapps-community-rdp/api/reference/royalapps-community-rdp-winforms-configuration-external-externalsessionconfiguration">ExternalSessionConfiguration.SelectedMonitors</a>.</p><p><a href="./../">Back to API index</a></p>',34)])])}const f=o(r,[["render",n]]);export{m as __pageData,f as default};
